sp_widget.client_script:
api.controller=function() {
	/* widget controller */
	var c = this;
	c.apps = JSON.parse(c.data.apps);

	c.getClassByIndex = function(index) {
		if (index === 0) {
			return 'text-right';
		} else if (index === 1) {
			return 'text-center';
		} else {
			return 'text-left';
		}
	};
};

sp_widget.css:
.gbd-apps-links {
  padding-bottom: 4rem;
  background-color: #f8f8f8;
}

.gov-title {
  text-align: center;
  color: #0c326f;
  font-weight: 600;
  font-size: 3.6rem;
  margin-top: 4rem;
  margin-bottom: 3.2rem;
  line-height: 1.5;
}

.gov-card {
  position: relative;
  display: inline-block;
  cursor: pointer;
}

.gov-card img {
  max-width: 100%;
}

.gov-card-hover {
  position: absolute;
  top: 0;
  left: 0;
  width: 100%;
  height: 100%;
  background-color: #5b5b5b;
  opacity: 0;
  transition: opacity 0.3s ease;
  color: #ffffff;
  padding: 20px;
}

.gov-card:hover .gov-card-hover {
  opacity: 1;
}

.gov-card-title {
  position: absolute;
  top: 20px;
  left: 0;
  right: 0;
  text-align: center;
  font-size: 20px;
  font-weight: 600;
}

.gov-card-stores {
  position: absolute;
  bottom: 20px;
  left: 0;
  right: 0;
  text-align: center;
}

.gov-card-stores img {
  width: 140px;
  margin: 5px 0;
}

.gov-cards-row {
  margin-bottom: 40px;
}

.gov-btn {
  border: 1px solid #0c326f;
  color: #0c326f;
  background-color: #ffffff;
  padding: 1rem 2.8rem;
  border-radius: 4.1rem;
  font-weight: 600;
  font-size: 1.6rem;
  text-transform: uppercase;
}

.gov-btn:hover {
  background: #1351b4;
  border-color: #1351b4;
  color: #fff;
  text-decoration: none;
}

sp_widget.script:
(function() {
	var appsString = gs.getProperty('x_821667_my_widget.gdb.app.links.apps', '{}');
	var appsJSON = JSON.parse(appsString);
	var apps = [];

	appsJSON.forEach(function(app) {
		apps.push({
			image: app.image,
			title: gs.getMessage(app.title),
			apple_link: app.apple_link,
			play_link: app.play_link
		});
	});

	data.apps = JSON.stringify(apps);
})();
